const uploadItem = $input.first();
const binaryEntries = Object.entries(uploadItem.binary || {});

const preferredKeys = ['artistImage', 'Image Upload', 'Image_Upload'];
const preferredEntry = preferredKeys
  .map((key) => [key, uploadItem.binary?.[key]])
  .find(([, value]) => value);

const imageEntry = preferredEntry || binaryEntries.find(([, value]) => {
  const mimeType = String(value?.mimeType || '').toLowerCase();
  return mimeType.startsWith('image/');
});

if (!imageEntry) {
  const binaryKeys = binaryEntries.map(([key]) => key).join(', ') || '(none)';
  throw new Error(`No uploaded image was found. Binary keys seen: ${binaryKeys}`);
}

const [binaryPropertyName, binaryInfo] = imageEntry;
const rawMimeType = String(binaryInfo.mimeType || 'image/png').toLowerCase();
const supportedMimeTypes = new Set(['image/jpeg', 'image/jpg', 'image/png', 'image/webp', 'image/gif']);
if (!supportedMimeTypes.has(rawMimeType)) {
  throw new Error(
    `Unsupported uploaded image MIME type: ${rawMimeType}. Use JPEG, PNG, WebP, or GIF.`
  );
}

const mimeType = rawMimeType === 'image/jpg' ? 'image/jpeg' : rawMimeType;
const fileName = binaryInfo.fileName || binaryPropertyName || 'uploaded-image';

let base64Data = '';
try {
  const imageBuffer = await this.helpers.getBinaryDataBuffer(0, binaryPropertyName);
  base64Data = imageBuffer.toString('base64');
} catch (error) {
  const inlineData = typeof binaryInfo.data === 'string' ? binaryInfo.data.trim() : '';
  if (inlineData) {
    base64Data = inlineData.replace(/\s+/g, '');
  } else {
    const message = error instanceof Error ? error.message : String(error);
    throw new Error(
      `Found uploaded image at binary.${binaryPropertyName}, but could not read its data. ${message}`
    );
  }
}

if (!/^[A-Za-z0-9+/=]+$/.test(base64Data)) {
  throw new Error(`Uploaded image data for ${binaryPropertyName} is not valid base64.`);
}

const estimatedBytes = Math.floor((base64Data.length * 3) / 4);
const maxRecommendedBytes = 20 * 1024 * 1024;
if (estimatedBytes > maxRecommendedBytes) {
  throw new Error(
    `Uploaded image is too large for vision chat (${Math.round(estimatedBytes / (1024 * 1024))} MB). Keep it under 20 MB.`
  );
}

const modelId = 'qwen3.5-35b-a3b-gguf-q4km';
const modelSelectionReason = 'Using the documented Sogni VLM model directly to keep the uploaded binary on the active item stream.';
const dataUrl = `data:${mimeType};base64,${base64Data}`;
const messages = [
  {
    role: 'system',
    content: 'You are a concise visual describer. Describe the uploaded image clearly, mention notable subjects, setting, colors, style, and any readable text. If uncertain, say so.'
  },
  {
    role: 'user',
    content: [
      {
        type: 'image_url',
        image_url: {
          url: dataUrl,
          detail: 'low'
        }
      },
      {
        type: 'text',
        text: 'Describe this uploaded image in 120 words or less.'
      }
    ]
  }
];

return {
  json: {
    fileName,
    mimeType,
    binaryPropertyName,
    imageBytesEstimated: estimatedBytes,
    dataUrlPrefix: dataUrl.slice(0, 80),
    modelId,
    modelName: modelId,
    modelSelectionReason,
    messages
  }
};

const result = $input.first().json;
const description = String(result.content || '').trim();

if (!description) {
  throw new Error('The Sogni LLM response was empty.');
}

const escapeHtml = (value) => value
  .replace(/&/g, '&amp;')
  .replace(/</g, '&lt;')
  .replace(/>/g, '&gt;')
  .replace(/"/g, '&quot;')
  .replace(/'/g, '&#39;');

const fileName = String(result.fileName || 'uploaded image');
const modelId = String(result.modelId || 'unknown-model');
const descriptionHtml = escapeHtml(description).replace(/\n/g, '<br>');

return {
  json: {
    ...result,
    completionTitle: 'Image Description',
    completionMessage: `<strong>File:</strong> ${escapeHtml(fileName)}<br><br>${descriptionHtml}<br><br><small>Model: ${escapeHtml(modelId)}</small>`
  }
};
